#include <stdio.h>
#include <string.h>
#define MAX_LINE 256
int main() {
    int T, N, Q;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        getchar(); // Consume newline
        char levels[15][11], messages[15][101];
        for (int i = 0; i < N; i++) {
            char line[MAX_LINE];
            fgets(line, MAX_LINE, stdin);
            line[strcspn(line, "\n")] = 0;
            char *tok = strtok(line, " ");
            tok = strtok(NULL, " ");
            strcpy(levels[i], tok ? tok : "");
            char *msg = strtok(NULL, "");
            if (msg) strncpy(messages[i], msg, 100); else messages[i][0] = '\0';
        }
        scanf("%d", &Q);
        getchar(); // Consume newline
        for (int qi = 0; qi < Q; qi++) {
            char line[MAX_LINE];
            fgets(line, MAX_LINE, stdin);
            line[strcspn(line, "\n")] = 0;
            char cmd[10], arg1[21], arg2[21];
            int cnt = sscanf(line, "%s %s %s", cmd, arg1, arg2);
            if (strcmp(cmd, "COUNT") == 0) {
                int ans = 0;
                for (int i = 0; i < N; i++) if (strcmp(levels[i], arg1) == 0) ans++;
                printf("%d\n", ans);
            } else if (strcmp(cmd, "SEARCH") == 0) {
                int ans = 0;
                for (int i = 0; i < N; i++) if (strstr(messages[i], arg1)) ans++;
                printf("%d\n", ans);
            } else if (strcmp(cmd, "FILTER") == 0) {
                int ans = 0;
                for (int i = 0; i < N; i++) if (strcmp(levels[i], arg1) == 0 && strstr(messages[i], arg2)) ans++;
                printf("%d\n", ans);
            } else {
                printf("0\n");
            }
        }
    }
    return 0;
}

