import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.StringTokenizer;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String[] lvl = new String[N];
            String[] msg = new String[N];
            for (int i = 0; i < N; i++) {
                String line = br.readLine();
                StringTokenizer st = new StringTokenizer(line);
                st.nextToken(); // timestamp
                lvl[i] = st.nextToken();
                int idx = line.indexOf(lvl[i]) + lvl[i].length();
                msg[i] = line.substring(idx).trim();
            }
            int Q = Integer.parseInt(br.readLine().trim());
            for (int q = 0; q < Q; q++) {
                String line = br.readLine();
                StringTokenizer st = new StringTokenizer(line);
                String cmd = st.nextToken();
                if (cmd.equals("COUNT")) {
                    String level = st.nextToken();
                    int ans = 0;
                    for (String l : lvl) if (l.equals(level)) ans++;
                    System.out.println(ans);
                } else if (cmd.equals("SEARCH")) {
                    String kw = st.nextToken();
                    int ans = 0;
                    for (String m : msg) if (m.contains(kw)) ans++;
                    System.out.println(ans);
                } else if (cmd.equals("FILTER")) {
                    String level = st.nextToken();
                    String kw = st.nextToken();
                    int ans = 0;
                    for (int i = 0; i < N; i++) if (lvl[i].equals(level) && msg[i].contains(kw)) ans++;
                    System.out.println(ans);
                } else {
                    System.out.println(0);
                }
            }
        }
    }
}

