const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
    const N = parseInt(lines[idx++]);
    let lvl = [];
    let msg = [];
    for (let i = 0; i < N; i++) {
        const line = lines[idx++];
        const parts = line.split(' ');
        const level = parts[1];
        const message = parts.slice(2).join(' ');
        lvl.push(level);
        msg.push(message);
    }
    const Q = parseInt(lines[idx++]);
    for (let q = 0; q < Q; q++) {
        const line = lines[idx++];
        const parts = line.split(' ');
        const cmd = parts[0];
        if (cmd === 'COUNT') {
            const level = parts[1];
            let cnt = 0;
            for (let i = 0; i < N; i++) if (lvl[i] === level) cnt++;
            out.push(String(cnt));
        } else if (cmd === 'SEARCH') {
            const kw = parts[1];
            let cnt = 0;
            for (let i = 0; i < N; i++) if (msg[i].includes(kw)) cnt++;
            out.push(String(cnt));
        } else if (cmd === 'FILTER') {
            const level = parts[1];
            const kw = parts[2];
            let cnt = 0;
            for (let i = 0; i < N; i++) if (lvl[i] === level && msg[i].includes(kw)) cnt++;
            out.push(String(cnt));
        } else {
            out.push('0');
        }
    }
}
